#!/usr/bin/env python3

import argparse
import sys
import json
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError, UnknownTopicOrPartitionError


def create_admin_client(bootstrap_servers):
    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=bootstrap_servers,
            client_id='kafka-admin-tool'
        )
        return admin_client
    except Exception as e:
        print(f"Error connecting to Kafka cluster: {e}")
        sys.exit(1)


def create_topics(admin_client, topic_configs):
    topics = []
    for config in topic_configs:
        topic_name = config['name']
        num_partitions = config.get('partitions', 1)
        replication_factor = config.get('replication_factor', 1)
        topic_configs_dict = config.get('config', {})
        
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs_dict
        )
        topics.append(new_topic)
    
    try:
        result = admin_client.create_topics(new_topics=topics, validate_only=False)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                print(f"Topic '{topic}' already exists")
            except Exception as e:
                print(f"Failed to create topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating topics: {e}")


def delete_topics(admin_client, topic_names):
    try:
        result = admin_client.delete_topics(topics=topic_names)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' deleted successfully")
            except UnknownTopicOrPartitionError:
                print(f"Topic '{topic}' does not exist")
            except Exception as e:
                print(f"Failed to delete topic '{topic}': {e}")
    except Exception as e:
        print(f"Error deleting topics: {e}")


def list_topics(admin_client):
    try:
        metadata = admin_client.list_topics()
        print("Available topics:")
        for topic in sorted(metadata):
            print(f"  - {topic}")
        return metadata
    except Exception as e:
        print(f"Error listing topics: {e}")
        return []


def describe_topics(admin_client, topic_names):
    try:
        metadata = admin_client._client.cluster
        for topic_name in topic_names:
            if topic_name in metadata.topics():
                topic = metadata.topics()[topic_name]
                print(f"\nTopic: {topic_name}")
                print(f"  Partitions: {len(topic)}")
                for partition_id in sorted(topic.keys()):
                    partition = topic[partition_id]
                    print(f"    Partition {partition_id}:")
                    print(f"      Leader: {partition.leader}")
                    print(f"      Replicas: {partition.replicas}")
                    print(f"      ISR: {partition.isr}")
            else:
                print(f"Topic '{topic_name}' not found")
    except Exception as e:
        print(f"Error describing topics: {e}")


def alter_topic_configs(admin_client, topic_name, configs):
    try:
        config_resource = ConfigResource(
            ConfigResourceType.TOPIC,
            topic_name,
            configs=configs
        )
        
        result = admin_client.alter_configs([config_resource])
        for resource, future in result.items():
            try:
                future.result()
                print(f"Configuration updated for topic '{topic_name}'")
            except Exception as e:
                print(f"Failed to update configuration for topic '{topic_name}': {e}")
    except Exception as e:
        print(f"Error altering topic configs: {e}")


def describe_topic_configs(admin_client, topic_names):
    try:
        config_resources = [
            ConfigResource(ConfigResourceType.TOPIC, topic_name)
            for topic_name in topic_names
        ]
        
        result = admin_client.describe_configs(config_resources)
        for resource, future in result.items():
            try:
                configs = future.result()
                print(f"\nConfiguration for topic '{resource.name}':")
                for config_key, config_value in configs.items():
                    print(f"  {config_key}: {config_value.value} (source: {config_value.source})")
            except Exception as e:
                print(f"Failed to describe configuration for topic '{resource.name}': {e}")
    except Exception as e:
        print(f"Error describing topic configs: {e}")


def create_partitions(admin_client, topic_partitions):
    try:
        from kafka.admin import NewPartitions
        
        partitions_dict = {}
        for topic_name, new_total in topic_partitions.items():
            partitions_dict[topic_name] = NewPartitions(total_count=new_total)
        
        result = admin_client.create_partitions(partitions_dict)
        for topic, future in result.items():
            try:
                future.result()
                print(f"Partitions updated for topic '{topic}'")
            except Exception as e:
                print(f"Failed to update partitions for topic '{topic}': {e}")
    except Exception as e:
        print(f"Error creating partitions: {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers (comma-separated)')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create topics')
    create_parser.add_argument('--topics', required=True, help='Topic configurations as JSON string or file path')
    create_parser.add_argument('--from-file', action='store_true', help='Read topics from JSON file')
    
    delete_parser = subparsers.add_parser('delete', help='Delete topics')
    delete_parser.add_argument('--topics', required=True, help='Comma-separated topic names')
    
    list_parser = subparsers.add_parser('list', help='List all topics')
    
    describe_parser = subparsers.add_parser('describe', help='Describe topics')
    describe_parser.add_argument('--topics', required=True, help='Comma-separated topic names')
    
    config_parser = subparsers.add_parser('config', help='Manage topic configurations')
    config_parser.add_argument('--topic', required=True, help='Topic name')
    config_parser.add_argument('--set', help='Set configuration as JSON string (e.g., {"retention.ms": "86400000"})')
    config_parser.add_argument('--describe', action='store_true', help='Describe topic configuration')
    
    partition_parser = subparsers.add_parser('partitions', help='Manage topic partitions')
    partition_parser.add_argument('--topic', required=True, help='Topic name')
    partition_parser.add_argument('--count', type=int, required=True, help='New total partition count')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    bootstrap_servers = [s.strip() for s in args.bootstrap_servers.split(',')]
    admin_client = create_admin_client(bootstrap_servers)
    
    try:
        if args.command == 'create':
            if args.from_file:
                with open(args.topics, 'r') as f:
                    topic_configs = json.load(f)
            else:
                topic_configs = json.loads(args.topics)
            
            if not isinstance(topic_configs, list):
                topic_configs = [topic_configs]
            
            create_topics(admin_client, topic_configs)
        
        elif args.command == 'delete':
            topic_names = [t.strip() for t in args.topics.split(',')]
            delete_topics(admin_client, topic_names)
        
        elif args.command == 'list':
            list_topics(admin_client)
        
        elif args.command == 'describe':
            topic_names = [t.strip() for t in args.topics.split(',')]
            describe_topics(admin_client, topic_names)
        
        elif args.command == 'config':
            if args.describe:
                describe_topic_configs(admin_client, [args.topic])
            elif args.set:
                configs = json.loads(args.set)
                alter_topic_configs(admin_client, args.topic, configs)
            else:
                print("Please specify --set or --describe")
        
        elif args.command == 'partitions':
            create_partitions(admin_client, {args.topic: args.count})
    
    finally:
        admin_client.close()


if __name__ == '__main__':
    main()